/// 页表更新后刷新本地 TLB。
pub fn flush_tlb() {
    // 安全性： 页表更新后执行 sfence.vma 是安全的。
    unsafe {
        asm!("sfence.vma");
    }
}

/// 写入代码页后刷新指令缓存。
pub fn flush_icache() {
