//! VirtIO 块设备（MMIO）驱动。

use core::cell::UnsafeCell;
use core::hint::spin_loop;
use core::ptr;
use core::sync::atomic::{fence, AtomicBool, AtomicUsize, Ordering};

use axfs::block::{BlockDevice, BlockId};
