//! Mount table and path resolution helpers.

use axvfs::{FileType, InodeId, VfsError, VfsOps, VfsResult};

/// Maximum path traversal depth to avoid unbounded recursion.
pub const MAX_PATH_DEPTH: usize = 64;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
/// Known mount identifiers.
pub enum MountId {
    Root,
    Dev,
    Proc,
}

/// A single mount point entry in the mount table.
pub struct MountPoint<'a> {
    /// Mount identifier.
    pub id: MountId,
    /// Mount path prefix.
    pub path: &'a str,
    /// Filesystem instance for this mount.
    pub fs: &'a dyn VfsOps,
}

impl<'a> MountPoint<'a> {
    /// Create a mount point definition.
    pub fn new(id: MountId, path: &'a str, fs: &'a dyn VfsOps) -> Self {
        Self { id, path, fs }
    }
}

/// Fixed-size mount table for resolving paths to filesystems.
pub struct MountTable<'a, const N: usize> {
    mounts: [MountPoint<'a>; N],
}

impl<'a, const N: usize> MountTable<'a, N> {
    /// Create a new mount table.
    pub fn new(mounts: [MountPoint<'a>; N]) -> Self {
        Self { mounts }
    }

    /// Resolve a path to the mount and inode.
    pub fn resolve_path(&self, path: &str) -> VfsResult<(MountId, InodeId)> {
        let (mount, rel) = self.find_mount(path)?;
        let inode = resolve_path_fs(mount.fs, rel)?;
        Ok((mount.id, inode))
    }

    /// Resolve the parent directory and basename for a path.
    pub fn resolve_parent<'p>(&self, path: &'p str) -> VfsResult<(MountId, InodeId, &'p str)> {
        if !path.starts_with('/') {
            return Err(VfsError::Invalid);
        }
        let trimmed = path.trim_end_matches('/');
        if trimmed == "/" {
            return Err(VfsError::Invalid);
        }
        let split = trimmed.rfind('/').ok_or(VfsError::Invalid)?;
        let (parent, name) = trimmed.split_at(split);
        let name = &name[1..];
        if name.is_empty() || name == "." || name == ".." {
            return Err(VfsError::Invalid);
        }
        let parent_path = if parent.is_empty() { "/" } else { parent };
        let (mount, rel) = self.find_mount(parent_path)?;
        let inode = resolve_path_fs(mount.fs, rel)?;
        Ok((mount.id, inode, name))
    }

    /// Return the filesystem for the given mount id.
    pub fn fs_for(&self, id: MountId) -> Option<&'a dyn VfsOps> {
        self.mounts.iter().find(|mount| mount.id == id).map(|mount| mount.fs)
    }

    /// Flush all mounted filesystems.
    pub fn flush_all(&self) -> VfsResult<()> {
        for mount in &self.mounts {
            mount.fs.flush()?;
        }
        Ok(())
    }

    fn find_mount<'p>(&self, path: &'p str) -> VfsResult<(&MountPoint<'a>, &'p str)> {
        if !path.starts_with('/') {
            return Err(VfsError::Invalid);
        }
        let mut best: Option<(&MountPoint<'a>, &str)> = None;
        for mount in &self.mounts {
            if let Some(rel) = match_mount_path(mount.path, path) {
                let replace = match best {
                    None => true,
                    Some((best_mount, _)) => mount.path.len() > best_mount.path.len(),
                };
                if replace {
                    best = Some((mount, rel));
                }
            }
        }
        best.ok_or(VfsError::NotFound)
    }
}

fn match_mount_path<'a>(mount_path: &str, path: &'a str) -> Option<&'a str> {
    if mount_path == "/" {
        return Some(path);
    }
    if path == mount_path {
        return Some("/");
    }
    if path.starts_with(mount_path) {
        let rest = &path[mount_path.len()..];
        if rest.starts_with('/') {
            return Some(rest);
        }
    }
    None
}

fn resolve_path_fs(fs: &dyn VfsOps, path: &str) -> VfsResult<InodeId> {
    let root = fs.root()?;
    if path.is_empty() || path == "/" {
        return Ok(root);
    }
    let mut current = root;
    let mut stack = [root; MAX_PATH_DEPTH];
    let mut depth = 1usize;
    for segment in path.split('/') {
        if segment.is_empty() || segment == "." {
            continue;
        }
        if segment == ".." {
            if depth > 1 {
                depth -= 1;
                current = stack[depth - 1];
            }
            continue;
        }
        let meta = fs.metadata(current)?;
        if meta.file_type != FileType::Dir {
            return Err(VfsError::NotDir);
        }
        let next = fs.lookup(current, segment)?.ok_or(VfsError::NotFound)?;
        current = next;
        if depth >= MAX_PATH_DEPTH {
            return Err(VfsError::Invalid);
        }
        stack[depth] = current;
        depth += 1;
    }
    if path.len() > 1 && path.ends_with('/') {
        let meta = fs.metadata(current)?;
        if meta.file_type != FileType::Dir {
            return Err(VfsError::NotDir);
        }
    }
    Ok(current)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::{devfs, memfs, procfs};

    #[test]
    fn resolve_mount_paths() {
        let rootfs = memfs::MemFs::new();
        let devfs = devfs::DevFs::new();
        let procfs = procfs::ProcFs::new();
        let mounts = MountTable::new([
            MountPoint::new(MountId::Root, "/", &rootfs),
            MountPoint::new(MountId::Dev, "/dev", &devfs),
            MountPoint::new(MountId::Proc, "/proc", &procfs),
        ]);
        let (mount, inode) = mounts.resolve_path("/").unwrap();
        assert_eq!(mount, MountId::Root);
        assert_eq!(inode, memfs::ROOT_ID);
        let (mount, inode) = mounts.resolve_path("/init").unwrap();
        assert_eq!(mount, MountId::Root);
        assert_eq!(inode, memfs::INIT_ID);
        let (mount, inode) = mounts.resolve_path("/dev").unwrap();
        assert_eq!(mount, MountId::Dev);
        assert_eq!(inode, devfs::ROOT_ID);
        let (mount, inode) = mounts.resolve_path("/dev/null").unwrap();
        assert_eq!(mount, MountId::Dev);
        assert_eq!(inode, devfs::DEV_NULL_ID);
        let (mount, inode) = mounts.resolve_path("/proc").unwrap();
        assert_eq!(mount, MountId::Proc);
        assert_eq!(inode, procfs::ROOT_ID);
    }

    #[test]
    fn resolve_parent_paths() {
        let rootfs = memfs::MemFs::new();
        let devfs = devfs::DevFs::new();
        let procfs = procfs::ProcFs::new();
        let mounts = MountTable::new([
            MountPoint::new(MountId::Root, "/", &rootfs),
            MountPoint::new(MountId::Dev, "/dev", &devfs),
            MountPoint::new(MountId::Proc, "/proc", &procfs),
        ]);
        let (mount, parent, name) = mounts.resolve_parent("/dev/null").unwrap();
        assert_eq!(mount, MountId::Dev);
        assert_eq!(parent, devfs::ROOT_ID);
        assert_eq!(name, "null");
        let (mount, parent, name) = mounts.resolve_parent("/proc").unwrap();
        assert_eq!(mount, MountId::Root);
        assert_eq!(parent, memfs::ROOT_ID);
        assert_eq!(name, "proc");
    }
}

//! Block device abstraction and a small write-back cache.

use axvfs::{VfsError, VfsResult};
use core::cell::UnsafeCell;
use core::hint::spin_loop;
use core::sync::atomic::{AtomicBool, Ordering};

/// Logical block identifier.
pub type BlockId = u64;

/// Abstract block device interface.
pub trait BlockDevice {
    /// Return the block size in bytes.
    fn block_size(&self) -> usize;
    /// Read a block into the provided buffer.
    fn read_block(&self, block_id: BlockId, buf: &mut [u8]) -> VfsResult<()>;
    /// Write a block from the provided buffer.
    fn write_block(&self, block_id: BlockId, buf: &[u8]) -> VfsResult<()>;
    /// Flush any buffered writes to the device.
    fn flush(&self) -> VfsResult<()>;
}

const BLOCK_CACHE_LINES: usize = 32;
const BLOCK_CACHE_MAX_SIZE: usize = 4096;

#[derive(Clone, Copy)]
struct CacheEntry {
    block_id: BlockId,
    valid: bool,
    dirty: bool,
    buf: [u8; BLOCK_CACHE_MAX_SIZE],
}

impl CacheEntry {
    const fn new() -> Self {
        Self {
            block_id: 0,
            valid: false,
            dirty: false,
            buf: [0u8; BLOCK_CACHE_MAX_SIZE],
        }
    }
}

struct CacheState {
    entries: [CacheEntry; BLOCK_CACHE_LINES],
}

impl CacheState {
    const fn new() -> Self {
        Self {
            entries: [CacheEntry::new(); BLOCK_CACHE_LINES],
        }
    }
}

struct CacheLock {
    locked: AtomicBool,
    state: UnsafeCell<CacheState>,
}

unsafe impl Sync for CacheLock {}

impl CacheLock {
    const fn new() -> Self {
        Self {
            locked: AtomicBool::new(false),
            state: UnsafeCell::new(CacheState::new()),
        }
    }

    fn lock(&self) -> CacheGuard<'_> {
        while self
            .locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            spin_loop();
        }
        CacheGuard { lock: self }
    }
}

struct CacheGuard<'a> {
    lock: &'a CacheLock,
}

impl<'a> CacheGuard<'a> {
    fn state_mut(&self) -> &mut CacheState {
        // SAFETY: guarded by spin lock.
        unsafe { &mut *self.lock.state.get() }
    }
}

impl Drop for CacheGuard<'_> {
    fn drop(&mut self) {
        self.lock.locked.store(false, Ordering::Release);
    }
}

/// Fixed-size block cache with a write-back policy.
pub struct BlockCache<'a> {
    device: &'a dyn BlockDevice,
    block_size: usize,
    cache: CacheLock,
}

impl<'a> BlockCache<'a> {
    /// Create a new block cache over a device.
    pub fn new(device: &'a dyn BlockDevice) -> Self {
        let block_size = device.block_size();
        Self {
            device,
            block_size,
            cache: CacheLock::new(),
        }
    }

    /// Return the block size in bytes.
    pub fn block_size(&self) -> usize {
        self.block_size
    }

    /// Read a block with caching.
    pub fn read_block(&self, block_id: BlockId, buf: &mut [u8]) -> VfsResult<()> {
        if buf.len() < self.block_size {
            return Err(VfsError::Invalid);
        }
        if self.block_size > BLOCK_CACHE_MAX_SIZE {
            return self.device.read_block(block_id, &mut buf[..self.block_size]);
        }
        let guard = self.cache.lock();
        let state = guard.state_mut();
        let index = (block_id as usize) % BLOCK_CACHE_LINES;
        let entry = &mut state.entries[index];
        if !entry.valid || entry.block_id != block_id {
            if entry.valid && entry.dirty {
                self.device
                    .write_block(entry.block_id, &entry.buf[..self.block_size])?;
                entry.dirty = false;
            }
            self.device
                .read_block(block_id, &mut entry.buf[..self.block_size])?;
            entry.block_id = block_id;
            entry.valid = true;
        }
        buf[..self.block_size].copy_from_slice(&entry.buf[..self.block_size]);
        Ok(())
    }

    /// Write a block with caching.
    pub fn write_block(&self, block_id: BlockId, buf: &[u8]) -> VfsResult<()> {
        if buf.len() < self.block_size {
            return Err(VfsError::Invalid);
        }
        if self.block_size > BLOCK_CACHE_MAX_SIZE {
            return self.device.write_block(block_id, &buf[..self.block_size]);
        }
        let guard = self.cache.lock();
        let state = guard.state_mut();
        let index = (block_id as usize) % BLOCK_CACHE_LINES;
        let entry = &mut state.entries[index];
        if entry.valid && entry.block_id != block_id && entry.dirty {
            self.device
                .write_block(entry.block_id, &entry.buf[..self.block_size])?;
        }
        entry.block_id = block_id;
        entry.valid = true;
        entry.dirty = true;
        entry.buf[..self.block_size].copy_from_slice(&buf[..self.block_size]);
        Ok(())
    }

    /// Flush dirty cache entries to the device.
    pub fn flush(&self) -> VfsResult<()> {
        if self.block_size <= BLOCK_CACHE_MAX_SIZE {
            let guard = self.cache.lock();
            let state = guard.state_mut();
            for entry in state.entries.iter_mut() {
                if entry.valid && entry.dirty {
                    self.device
                        .write_block(entry.block_id, &entry.buf[..self.block_size])?;
                    entry.dirty = false;
                }
            }
        }
        self.device.flush()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use core::cell::RefCell;

    struct TestBlockDevice {
        block_size: usize,
        data: RefCell<[u8; 8]>,
    }

    impl BlockDevice for TestBlockDevice {
        fn block_size(&self) -> usize {
            self.block_size
        }

        fn read_block(&self, block_id: BlockId, buf: &mut [u8]) -> VfsResult<()> {
            let offset = block_id as usize * self.block_size;
            let data = self.data.borrow();
            if offset + self.block_size > data.len() {
                return Err(VfsError::NotFound);
            }
            buf[..self.block_size].copy_from_slice(&data[offset..offset + self.block_size]);
            Ok(())
        }

        fn write_block(&self, block_id: BlockId, buf: &[u8]) -> VfsResult<()> {
            let offset = block_id as usize * self.block_size;
            let mut data = self.data.borrow_mut();
            if offset + self.block_size > data.len() {
                return Err(VfsError::NotFound);
            }
            data[offset..offset + self.block_size].copy_from_slice(&buf[..self.block_size]);
            Ok(())
        }

        fn flush(&self) -> VfsResult<()> {
            Ok(())
        }
    }

    #[test]
    fn block_cache_passthrough() {
        let dev = TestBlockDevice {
            block_size: 4,
            data: RefCell::new([0u8; 8]),
        };
        let cache = BlockCache::new(&dev);
        let buf = [1u8, 2, 3, 4];
        cache.write_block(1, &buf).unwrap();
        let mut read = [0u8; 4];
        cache.read_block(1, &mut read).unwrap();
        assert_eq!(read, buf);
    }

    #[test]
    fn block_cache_writeback_flush() {
        let dev = TestBlockDevice {
            block_size: 4,
            data: RefCell::new([0u8; 8]),
        };
        let cache = BlockCache::new(&dev);
        let buf = [7u8, 7, 7, 7];
        cache.write_block(0, &buf).unwrap();

        let mut direct = [0u8; 4];
        dev.read_block(0, &mut direct).unwrap();
        assert_ne!(direct, buf);

        cache.flush().unwrap();
        dev.read_block(0, &mut direct).unwrap();
        assert_eq!(direct, buf);
    }
}

//! ext4 文件系统实现。
//!
//! 中文注释：这里实现的是“最小可用”的 ext4 子集，主要面向 Aurora 的根文件系统。
//! - 支持：超级块/块组描述符/位图、inode、目录项遍历、读写/创建/截断。
//! - 寻址：同时支持 extent 树与传统间接块，但写入路径只实现了最小集。
//! - 简化：只在第 0 块组分配 inode/数据块，不做跨块组均衡。
//! - 不支持：日志(journal)、metadata_csum 校验、复杂特性（配额/xattr/ACL）。
//! - 风险：元数据校验未维护，宿主机工具可能提示“校验不一致”。

use axvfs::{DirEntry, FileType, InodeId, Metadata, VfsError, VfsOps, VfsResult};
use core::cell::UnsafeCell;
use core::hint::spin_loop;
use core::sync::atomic::{AtomicBool, Ordering};

use crate::block::{BlockCache, BlockDevice, BlockId};

// ====== 磁盘结构相关常量 ======
// ext4 根目录 inode 固定为 2。
const EXT4_ROOT_INODE: InodeId = 2;
// ext4 魔数。
const EXT4_MAGIC: u16 = 0xef53;
// 超级块位于偏移 1024 字节处，大小固定 1024 字节。
const SUPERBLOCK_OFFSET: u64 = 1024;
const SUPERBLOCK_SIZE: usize = 1024;
// 超级块字段偏移（只取本实现需要的最小集合）。
const SUPERBLOCK_LOG_BLOCK_SIZE_OFFSET: usize = 24;
const SUPERBLOCK_BLOCKS_PER_GROUP_OFFSET: usize = 32;
const SUPERBLOCK_INODES_PER_GROUP_OFFSET: usize = 40;
const SUPERBLOCK_MAGIC_OFFSET: usize = 56;
const SUPERBLOCK_INODE_SIZE_OFFSET: usize = 88;
// 块组描述符大小与字段偏移。
const GROUP_DESC_SIZE: usize = 32;
const GROUP_DESC_BLOCK_BITMAP_OFFSET: usize = 0;
const GROUP_DESC_INODE_BITMAP_OFFSET: usize = 4;
const GROUP_DESC_INODE_TABLE_OFFSET: usize = 8;
// inode 结构中的字段偏移（仅解析所需字段）。
const INODE_MODE_OFFSET: usize = 0;
const INODE_SIZE_LO_OFFSET: usize = 4;
const INODE_FLAGS_OFFSET: usize = 32;
const INODE_BLOCK_OFFSET: usize = 40;
const INODE_BLOCK_LEN: usize = 60;
const INODE_SIZE_HIGH_OFFSET: usize = 108;
// extents 标志位（inode.flags 中）。
const EXT4_EXTENTS_FLAG: u32 = 0x0008_0000;
// extent header/entry 相关常量。
const EXTENT_HEADER_MAGIC: u16 = 0xf30a;
const EXTENT_HEADER_SIZE: usize = 12;
const EXTENT_ENTRY_SIZE: usize = 12;
const EXTENT_LEN_MAX: u16 = 0x7fff;
const EXTENT_INODE_CAPACITY: usize = (INODE_BLOCK_LEN - EXTENT_HEADER_SIZE) / EXTENT_ENTRY_SIZE;
// scratch 缓冲区大小（与最大支持块大小一致）。
const EXT4_SCRATCH_SIZE: usize = 4096;
// inode mode 的类型位。
const EXT4_MODE_DIR: u16 = 0x4000;
const EXT4_MODE_FILE: u16 = 0x8000;
// 目录项 header 以及类型码。
const EXT4_DIR_ENTRY_HEADER: usize = 8;
const EXT4_DIR_ENTRY_FILE: u8 = 1;
const EXT4_DIR_ENTRY_DIR: u8 = 2;
const EXT4_DIR_ENTRY_CHAR: u8 = 3;
const EXT4_DIR_ENTRY_BLOCK: u8 = 4;
const EXT4_DIR_ENTRY_FIFO: u8 = 5;
const EXT4_DIR_ENTRY_SOCKET: u8 = 6;
const EXT4_DIR_ENTRY_SYMLINK: u8 = 7;
// inode.blocks 中前 12 个为直接块指针（经典 ext2/3/4 格式）。
const EXT4_DIRECT_BLOCKS: usize = 12;

// 全局 scratch 缓冲区：解析/构造元数据时复用，避免堆分配，用自旋锁串行访问。
// 注意：这意味着所有读写都会串行化，换取实现简单。
struct ScratchLock {
    locked: AtomicBool,
    buf: UnsafeCell<[u8; EXT4_SCRATCH_SIZE]>,
}

unsafe impl Sync for ScratchLock {}

impl ScratchLock {
    // 初始化 scratch 锁与缓冲区。
    const fn new() -> Self {
        Self {
            locked: AtomicBool::new(false),
            buf: UnsafeCell::new([0u8; EXT4_SCRATCH_SIZE]),
        }
    }

    // 获取互斥访问权（自旋等待）。
    fn lock(&self) -> ScratchGuard<'_> {
        while self
            .locked
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            spin_loop();
        }
        ScratchGuard { lock: self }
    }
}

struct ScratchGuard<'a> {
    lock: &'a ScratchLock,
}

impl<'a> ScratchGuard<'a> {
    // 返回可变缓冲区引用，生命周期由 guard 控制。
    fn get_mut(&self) -> &mut [u8; EXT4_SCRATCH_SIZE] {
        // 安全性： guard 确保对 scratch 缓冲区的独占访问。
        unsafe { &mut *self.lock.buf.get() }
    }
}

impl Drop for ScratchGuard<'_> {
    // 释放锁。
    fn drop(&mut self) {
        self.lock.locked.store(false, Ordering::Release);
    }
}

static EXT4_SCRATCH: ScratchLock = ScratchLock::new();

#[derive(Clone, Copy, Debug)]
/// 本实现需要的 ext4 超级块字段。
/// 仅解析本实现需要的字段，忽略其他 ext4 特性位。
/// 字段偏移来自 ext4 超级块布局（1KiB 处）。
pub struct SuperBlock {
    /// log2(block_size / 1024)。
    pub log_block_size: u32,
    /// 每组块数。
    pub blocks_per_group: u32,
    /// 每组 inode 数。
    pub inodes_per_group: u32,
    /// inode 大小（字节）。
    pub inode_size: u16,
    /// ext4 魔数。
    pub magic: u16,
}

impl SuperBlock {
    /// 从给定缓冲解析超级块。
    /// 校验 magic，并检查 block size / inode size 是否处于可支持范围。
    pub fn parse(buf: &[u8]) -> VfsResult<Self> {
        if buf.len() < SUPERBLOCK_SIZE {
            return Err(VfsError::Invalid);
        }
        let magic = read_u16(buf, SUPERBLOCK_MAGIC_OFFSET);
        if magic != EXT4_MAGIC {
            return Err(VfsError::Invalid);
        }
        let log_block_size = read_u32(buf, SUPERBLOCK_LOG_BLOCK_SIZE_OFFSET);
        let blocks_per_group = read_u32(buf, SUPERBLOCK_BLOCKS_PER_GROUP_OFFSET);
        let inodes_per_group = read_u32(buf, SUPERBLOCK_INODES_PER_GROUP_OFFSET);
        let inode_size = read_u16(buf, SUPERBLOCK_INODE_SIZE_OFFSET);
        // ext4 约定 block_size = 1024 << log_block_size。
        let block_size = 1024u32.checked_shl(log_block_size).ok_or(VfsError::Invalid)?;
        if block_size < 1024 || !block_size.is_power_of_two() || inode_size == 0 {
            return Err(VfsError::Invalid);
        }
        Ok(Self {
            log_block_size,
            blocks_per_group,
            inodes_per_group,
            inode_size,
            magic,
        })
    }

    /// 返回文件系统块大小（字节）。
    pub fn block_size(&self) -> u32 {
        1024u32 << self.log_block_size
    }
}

#[derive(Clone, Copy, Debug)]
/// 块组描述符：只使用位图和 inode 表的起始块号。
/// 注意：这里没有解析 free counts，也不更新 group 统计信息。
struct GroupDesc {
    block_bitmap: u32,
    inode_bitmap: u32,
    inode_table: u32,
}

impl GroupDesc {
    // 解析块组描述符，提取位图与 inode 表位置。
    fn parse(buf: &[u8]) -> VfsResult<Self> {
        if buf.len() < GROUP_DESC_SIZE {
            return Err(VfsError::Invalid);
        }
        let block_bitmap = read_u32(buf, GROUP_DESC_BLOCK_BITMAP_OFFSET);
        let inode_bitmap = read_u32(buf, GROUP_DESC_INODE_BITMAP_OFFSET);
        let inode_table = read_u32(buf, GROUP_DESC_INODE_TABLE_OFFSET);
        if block_bitmap == 0 || inode_bitmap == 0 || inode_table == 0 {
            return Err(VfsError::Invalid);
        }
        Ok(Self {
            block_bitmap,
            inode_bitmap,
            inode_table,
        })
    }
}

