    fn truncate(&self, inode: InodeId, size: u64) -> VfsResult<()> {
        let mut inode_meta = self.read_inode(inode)?;
        if inode_mode_type(inode_meta.mode) == FileType::Dir {
            return Err(VfsError::NotDir);
        }
        if size <= inode_meta.size {
