pub fn switch_root(root_pa: usize) {
    if root_pa == 0 {
        return;
    }
    let satp_value = satp_for_root(root_pa);
    // 安全性： 切换 satp 需要 sfence.vma 同步 TLB。
    unsafe {
        asm!("csrw satp, {0}", in(reg) satp_value);
