    let mut stack_pa = 0usize;
    for idx in 0..USER_STACK_PAGES {
        let va = USER_STACK_VA + idx * PAGE_SIZE;
        let pa = ensure_user_page(root_pa, va, mm::UserAccess::Write, mm::map_user_stack)?;
        if idx == 0 {
            stack_pa = pa;
        }
        // 安全性： 恒等映射的页帧；清空每个栈页。
        unsafe {
            ptr::write_bytes(pa as *mut u8, 0, PAGE_SIZE);
