    if stack_pa == 0 {
        return None;
    }

    init_user_image(code_pa, data_pa, message_pa, stack_pa);
    mm::flush_icache();
    mm::flush_tlb();

    Some(UserContext {
        entry: USER_CODE_VA,
        user_sp: USER_STACK_VA + USER_STACK_SIZE,
        root_pa,
        satp: mm::satp_for_root(root_pa),
        argc: 0,
        argv: 0,
        envp: 0,
        heap_top: USER_MESSAGE_PAGE_VA + PAGE_SIZE,
